const inputItem = $input.first();

// 실제 폼 필드명으로 접근
const agencyName = inputItem.json['기관명을 입력하세요'] || '';
const uploadedFiles = inputItem.json['증적자료를 업로드하세요'] || [];
const binary = inputItem.binary || {};
const binaryKeys = Object.keys(binary);

if (uploadedFiles.length === 0) throw new Error('업로드된 파일이 없습니다.');

const items = [];
for (let i = 0; i < uploadedFiles.length; i++) {
  const binaryKey = binaryKeys[i];
  if (!binaryKey) continue;
  items.push({
    json: {
      fileIndex: i,
      filename: uploadedFiles[i].filename,
      agencyName,
      totalFiles: uploadedFiles.length
    },
    binary: { data: binary[binaryKey] }
  });
}

if (items.length === 0) throw new Error('바이너리 데이터를 찾을 수 없습니다.');
return items;

// Gemini Files API 응답에서 file_uri 추출 + generateContent 요청 바디 조립
// ※ JSON 전용 처리 — binary 접근 없음 (Task Runner 호환)
const results = [];
const uploadResults = $input.all();
const originalItems = $('파일 정규화').all();

for (let i = 0; i < uploadResults.length; i++) {
  const uploadItem = uploadResults[i];
  const originalItem = originalItems[i] || { json: {} };

  const fileUri = uploadItem.json?.file?.uri;
  const filename = originalItem.json.filename || `file_${i + 1}.pdf`;
  const fileIndex = originalItem.json.fileIndex ?? i;
  const agencyName = originalItem.json.agencyName ?? '';

  if (!fileUri) {
    throw new Error(`[${filename}] 파일 업로드 응답에 URI가 없습니다. 응답: ${JSON.stringify(uploadItem.json)}`);
  }

  const geminiRequestBody = {
    contents: [{
      parts: [
        {
          file_data: {
            mime_type: 'application/pdf',
            file_uri: fileUri
          }
        },
        {
          text: `파일명: "${filename}"\n\n이 PDF 파일의 전체 내용을 텍스트로 상세히 추출해주세요.\n- 표가 있으면 표의 내용을 텍스트로 정리해주세요.\n- 이미지·그래픽이 있으면 그 내용과 의미를 설명해주세요.\n- 원문에 충실하게 추출하되, 레이아웃·페이지 구분 마크업은 생략해도 됩니다.\n- 최대한 완전하게 추출해주세요.`
        }
      ]
    }],
    generationConfig: {
      maxOutputTokens: 8192
    }
  };

  results.push({
    json: {
      fileIndex,
      filename,
      agencyName,
      fileUri,
      geminiRequestBody
    }
  });
}

return results;

// Gemini generateContent 응답 파싱 + 파일 역할 판별 (본체 vs 보조자료)
return $input.all().map(item => {
  const filename = item.json.filename ?? '파일명 없음';

  // Gemini API 응답에서 추출 텍스트 가져오기
  const candidates = item.json.candidates;
  let extractedText = '';
  if (candidates?.[0]?.content?.parts?.[0]?.text) {
    extractedText = candidates[0].content.parts[0].text;
  }

  // 파일 역할 판별: 파일명에 아래 키워드가 포함되면 보조자료(support)
  const supportKeywords = [
    '계획서', '계획(안)', '계획안', '결과요약서', '결과보고서',
    '보고서(안)', '보조자료', '공문', '지침', '가이드', '증빙'
  ];
  const isSupport = supportKeywords.some(kw => filename.includes(kw));

  return {
    json: {
      fileIndex: item.json.fileIndex ?? 0,
      filename,
      agencyName: item.json.agencyName ?? '',
      role: isSupport ? 'support' : 'main',
      text: extractedText.trim().substring(0, 15000)
    }
  };
});

const inputData = $input.first().json;
const files = inputData.files || [];
const agencyName = (files[0] || {}).agencyName || '';

const mainFiles = files.filter(f => f.role === 'main');
const supportFiles = files.filter(f => f.role === 'support');

// 본체 파일 목록을 명시적으로 번호 나열
const mainFileList = mainFiles.map((f, i) => `  ${i+1}. ${f.filename}`).join('\n');

const mainText = mainFiles.length > 0
  ? '【주요 실적 파일 (본체 — 실적 자체)】\n' +
    mainFiles.map((f, i) =>
      '[본체파일 ' + (i+1) + '번] ' + f.filename + '\n' + (f.text || '(내용 없음)')
    ).join('\n\n---\n\n')
  : '';

const supportText = supportFiles.length > 0
  ? '\n\n【보조 자료 파일 (계획서·계획(안) 등 — 실적 수에 포함 안 됨)】\n' +
    supportFiles.map((f, i) =>
      '[보조파일 ' + (i+1) + '번] ' + f.filename + '\n' + (f.text || '(내용 없음)')
    ).join('\n\n---\n\n')
  : '';

return [{
  json: {
    agencyName,
    fileCount: files.length,
    mainFileCount: mainFiles.length,
    supportFileCount: supportFiles.length,
    mainFileList,
    fileListText: (mainText + supportText).substring(0, 50000)
  }
}];

// AI 출력 정제화 + 첨부7 양식 HTML 변환
const outputRaw = $input.first().json.output;

// 1) JSON 추출: 다양한 포맷 대응 (코드펜스, 앞뒤 텍스트, 순수 JSON 모두)
function extractJSON(str) {
  if (typeof str !== 'string') return str;

  // 방법 1: ```json ... ``` 블록 추출
  const fenceMatch = str.match(/```json[\s\S]*?({[\s\S]*?})[\s\S]*?```/);
  if (fenceMatch) return fenceMatch[1].trim();

  // 방법 2: ``` ... ``` 블록 추출
  const fenceMatch2 = str.match(/```[\s\S]*?({[\s\S]*?})[\s\S]*?```/);
  if (fenceMatch2) return fenceMatch2[1].trim();

  // 방법 3: 첫 번째 { 부터 마지막 } 까지 추출 (앞뒤 설명 텍스트 제거)
  const firstBrace = str.indexOf('{');
  const lastBrace = str.lastIndexOf('}');
  if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
    return str.substring(firstBrace, lastBrace + 1).trim();
  }

  return str.trim();
}

// 2) Gemini가 다른 필드명으로 돌려줄 때 정규화
function normalizeData(raw) {
  if (!raw) return { achievements: [], summary: '' };

  if (Array.isArray(raw.achievements) && raw.achievements.length > 0) return raw;

  const src = raw.report || raw.results || raw['실적'] || [];
  const achievements = src.map(function(item, i) {
    var bg = item.background || item.backgroundAndPurpose || item['추진배경'] || item['추진배경및목적'] || '';
    if (item.purpose && !bg.includes(item.purpose)) bg = (bg + '\n\n■ 목적: ' + item.purpose).trim();
    return {
      achievementNumber: item.achievementNumber || item.number || (i + 1),
      type: item.type || item['유형'] || '기타',
      title: item.title || item['제목'] || item.name || '',
      relatedFiles: item.relatedFiles || item.files || [],
      background: bg,
      target: item.target || item['추진대상'] || '',
      content: item.content || item['추진내용'] || '',
      outcome: item.outcome || item.result || item.achievementAndExpectedEffect
             || item.achievementResult || item['추진성과'] || item['기대효과'] || ''
    };
  });

  return {
    achievements: achievements,
    summary: raw.summary || ('접수된 파일을 분석하여 선별한 대표 실적 ' + achievements.length + '건입니다.')
  };
}

var data;
try {
  var cleaned = extractJSON(outputRaw);
  data = normalizeData(JSON.parse(cleaned));
} catch(e) {
  // 파싱 실패 시 원본 텍스트도 같이 기록
  data = { achievements: [], summary: '⚠️ 출력 파싱 실패. n8n 실행 로그를 확인해주세요. (' + String(e.message) + ')\n\n[원본 출력 앞 500자]\n' + String(outputRaw || '').substring(0, 500) };
}

