function extractJSON(str) {
  if (typeof str !== 'string') return str;

  // 방법 1: ```json ... ``` 블록 추출
  const fenceMatch = str.match(/```json[\s\S]*?({[\s\S]*?})[\s\S]*?```/);
  if (fenceMatch) return fenceMatch[1].trim();

  // 방법 2: ``` ... ``` 블록 추출
  const fenceMatch2 = str.match(/```[\s\S]*?({[\s\S]*?})[\s\S]*?```/);
  if (fenceMatch2) return fenceMatch2[1].trim();

  // 방법 3: 첫 번째 { 부터 마지막 } 까지 추출 (앞뒤 설명 텍스트 제거)
  const firstBrace = str.indexOf('{');
  const lastBrace = str.lastIndexOf('}');
  if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
    return str.substring(firstBrace, lastBrace + 1).trim();
  }

  return str.trim();
}

